import random

# List of sensitive data types
sensitive_data_types = ["passwords", "credit card numbers", "social security numbers", "personal emails", "medical records"]

# Simulating the extraction process
def extract_sensitive_data():
    print("Simulating the extraction of sensitive data from the computer system...")
    extracted_data = []

    # Generating random sensitive data
    num_data = random.randint(1, 5)
    for _ in range(num_data):
        data_type = random.choice(sensitive_data_types)
        data = generate_random_data(data_type)
        extracted_data.append((data_type, data))

    return extracted_data

# Generating random data based on data type
def generate_random_data(data_type):
    if data_type == "passwords":
        return "P@ssw0rd123"
    elif data_type == "credit card numbers":
        return "1234-5678-9012-3456"
    elif data_type == "social security numbers":
        return "123-45-6789"
    elif data_type == "personal emails":
        return "john.doe@example.com"
    elif data_type == "medical records":
        return "Patient has a history of allergies."
    else:
        return "Random data"

# Main program
if __name__ == "__main__":
    extracted_data = extract_sensitive_data()

    print("Extracted sensitive data:")
    for data_type, data in extracted_data:
        print(f"{data_type}: {data}")

    print("Extraction process completed.")
